export const validateCatalog = (catalog = giftCatalog) => {
  const ids = new Set();
  const errors = [];

  catalog.forEach((item) => {
    if (!item.id || ids.has(item.id)) errors.push(`Duplicate or missing id: ${item.id || 'unknown'}`);
    ids.add(item.id);
    if (!item.name || !item.category || !item.searchTerm) errors.push(`Incomplete gift: ${item.id}`);
    if (!categoryDetails[item.category]) errors.push(`Unknown category for ${item.id}: ${item.category}`);
    if (!item.budgets?.length) errors.push(`Missing budget for ${item.id}`);
  });

  return errors;
};
